INSERT INTO `course_units` (`id`, `action_user`, `course_id`, `unit_type`, `unit_code`, `unit_name`, `descriptions`, `total_files`, `is_published`, `created_at`, `updated_at`, `deleted_at`) VALUES
(1, 1, 1, 'core', 'SHBBBOS002', 'Provide Body Massages', '<p>This qualification reflects the role of individuals employed as beauty therapists to provide a broad range of beauty therapy treatments and services including facial treatments, body massage and treatments, hair removal, lash and brow treatments, nail and make-up services. This includes consultation with clients to provide beauty advice, recommend beauty treatments and services, and sell retail skin-care and cosmetic products. These individuals work relatively autonomously, and are accountable for personal outputs. Their work involves the self-directed application of knowledge and skills with substantial depth in some areas where judgement is required in planning and selecting appropriate equipment, services and techniques. Work is typically conducted in beauty salons and spas. No occupational licensing, certification or specific legislative requirements apply to this qualification at the time of publication.</p>', 0, 'n', '2021-03-09 12:07:33', '2021-03-09 12:07:33', NULL),
